// This is the raw logic the Runnore app will download and execute
module.exports = {
    activate: function(editor) {
        console.log("Luau Prettier Activated!");
        editor.addCommand(monaco.KeyMod.CtrlCmd | monaco.KeyCode.KeyS, function() {
            const code = editor.getValue();
            // Format logic here...
            editor.setValue(code + "\n-- Formatted by Luau Prettier Pro");
        });
    },
    deactivate: function() {
        console.log("Luau Prettier Deactivated");
    }
}
